script:
frappe.listview_settings['Customer'] = frappe.listview_settings['Customer'] || {};
(function () {
	function openImportDialog() {
		frappe.call('erpnext_custom.customer_import.preview_crm_import').then(function (r) {
			var m = (r && r.message) || {};
			var d = new frappe.ui.Dialog({
				title: __('Import CRM Organization → Customer'),
				fields: [
					{ fieldname: 'scope', fieldtype: 'Select', label: __('Yang diimpor'), reqd: 1, default: 'operational',
					  options: ['operational', 'won_deals', 'all'].join('\n') },
					{ fieldname: 'info', fieldtype: 'HTML' },
				],
				primary_action_label: __('Import'),
				primary_action: function (v) {
					var scope = v.scope || 'operational';
					var count = m[scope] || 0;
					d.hide();
					if (!count) { frappe.msgprint(__('Tidak ada yang perlu diimpor untuk pilihan ini (semua sudah ada).')); return; }
					var bg = count > 100;
					frappe.call({
						method: bg ? 'erpnext_custom.customer_import.enqueue_crm_import' : 'erpnext_custom.customer_import.import_from_crm_organization',
						args: { scope: scope }, freeze: !bg, freeze_message: __('Mengimpor…'),
					}).then(function (rr) {
						var res = (rr && rr.message) || {};
						if (bg) {
							frappe.show_alert({ message: __('Import "{0}" jalan di background ({1} record). Refresh sebentar lagi.', [scope, count]), indicator: 'blue' });
						} else {
							frappe.show_alert({ message: __('Selesai: {0} dibuat, {1} dilewati.', [res.created || 0, res.skipped || 0]), indicator: 'green' });
							if (window.cur_list && cur_list.doctype === 'Customer') cur_list.refresh();
						}
					});
				},
			});
			var render = function () {
				var sc = d.get_value('scope') || 'operational';
				var labels = { operational: __('Operational (dipakai di Shipping/Packing/Expense)'), won_deals: __('Dari Deal menang (Won)'), all: __('Semua CRM Organization') };
				d.fields_dict.info.$wrapper.html(
					'<div style="font-size:12px;line-height:1.7;padding:4px 0;"><b>' + (m[sc] || 0) + '</b> akan diimpor untuk: ' +
					frappe.utils.escape_html(labels[sc] || sc) + '.<br><span class="text-muted">Operational: ' + (m.operational || 0) +
					' · Won: ' + (m.won_deals || 0) + ' · Semua: ' + (m.all || 0) + ' · sudah ada: ' + (m.already || 0) +
					' / total CRM Org ' + (m.total_org || 0) + '</span></div>'
				);
			};
			d.fields_dict.scope.df.onchange = render;
			d.show();
			render();
		});
	}
	function importBtn(lv) {
		if (!lv || !lv.page || lv.__crmImportBtn) return;
		lv.__crmImportBtn = true;
		lv.page.add_inner_button(__('⬆ Import dari CRM Organization'), openImportDialog);
	}
	var prev = frappe.listview_settings['Customer'].onload;
	frappe.listview_settings['Customer'].onload = function (lv) { if (prev) { try { prev(lv); } catch (e) {} } importBtn(lv); };
	if (window.cur_list && window.cur_list.doctype === 'Customer') importBtn(window.cur_list);
})();
